#include <iostream>
#include <string>

using namespace std;

struct TreeNode {
    int val;
    TreeNode *left, *right;
    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
};

void serialize(TreeNode* node, string &out)
{
    if (node == nullptr) { out += "#,"; return; }
    out += to_string(node->val) + ",";
    serialize(node->left, out);
    serialize(node->right, out);
}

bool isSameTree(TreeNode* p, TreeNode* q)
{
    string sp, sq;
    serialize(p, sp);
    serialize(q, sq);
    return sp == sq;
}

int main()
{
    TreeNode* p = new TreeNode(1); p->left = new TreeNode(2); p->right = new TreeNode(3);
    TreeNode* q = new TreeNode(1); q->left = new TreeNode(2); q->right = new TreeNode(3);

    cout << (isSameTree(p, q) ? "true" : "false") << endl;

    return 0;
}

#include <iostream>

using namespace std;

struct TreeNode {
    int val;
    TreeNode *left, *right;
    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
};

bool isSameTree(TreeNode* p, TreeNode* q)
{
    if (p == nullptr && q == nullptr) return true;
    if (p == nullptr || q == nullptr) return false;

    return p->val == q->val && isSameTree(p->left, q->left) && isSameTree(p->right, q->right);
}

int main()
{
    TreeNode* p = new TreeNode(1); p->left = new TreeNode(2); p->right = new TreeNode(3);
    TreeNode* q = new TreeNode(1); q->left = new TreeNode(2); q->right = new TreeNode(3);

    cout << (isSameTree(p, q) ? "true" : "false") << endl;

    return 0;
}

